 func (c *Client) GetSessionInDirectory(sessionID, directory string) (*Session, error) {
 	req, err := http.NewRequest("GET", c.ServerURL+"/session/"+sessionID, nil)
 	if err != nil {
 		return nil, fmt.Errorf("failed to create request: %w", err)
 	}
